SELECT d.* FROM device d inner join store_address s on s.storeAddrId= d.storeAddressId where 1=1
AND s.storeId=#{storeId}
AND s.storeId in (${storeIds})
AND d.deviceNo LIKE concat('%',#{deviceNo},'%')
AND d.phone LIKE concat('%',#{phone},'%')
AND d.status = #{status}
order BY d.createTime desc
limit #{offset}, #{limit}

